@page "/"
@attribute [Authorize]

@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>VetClinic Dashboard</PageTitle>

<h1>Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card text-center">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="display-4">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-center">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="display-4">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-center">
            <div class="card-body">
                <h5 class="card-title">Total Patients</h5>
                <p class="display-4">@totalPatients</p>
            </div>
        </div>
    </div>
</div>

<div class="row mb-4">
    <div class="col-md-12">
        <h4>Quick Actions</h4>
        <a href="/patients" class="btn btn-primary me-2">Add Patient</a>
        <a href="/appointments" class="btn btn-success me-2">Schedule Appointment</a>
        <a href="/billing" class="btn btn-warning me-2">Create Invoice</a>
    </div>
</div>

<div class="row">
    <div class="col-md-6">
        <h4>Recent Patients</h4>
        @if (recentPets.Any())
        {
            <table class="table table-sm">
                <thead><tr><th>Name</th><th>Species</th><th>Owner</th></tr></thead>
                <tbody>
                    @foreach (var pet in recentPets)
                    {
                        <tr>
                            <td><a href="/patients/@pet.Id">@pet.Name</a></td>
                            <td>@pet.Species</td>
                            <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No patients registered yet.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Today's Schedule</h4>
        @if (todaySchedule.Any())
        {
            <table class="table table-sm">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th></tr></thead>
                <tbody>
                    @foreach (var appt in todaySchedule)
                    {
                        <tr>
                            <td>@appt.ScheduledDateTime.ToString("HH:mm")</td>
                            <td>@appt.Pet.Name</td>
                            <td>@appt.Reason</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No appointments today.</p>
        }
    </div>
</div>

@code {
    private int todayAppointments;
    private int pendingInvoices;
    private int totalPatients;
    private List<Pet> recentPets = new();
    private List<Appointment> todaySchedule = new();

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var today = DateTime.Today;

        todayAppointments = await db.Appointments
            .CountAsync(a => a.ScheduledDateTime.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Sent || i.Status == InvoiceStatus.Overdue);
        totalPatients = await db.Pets.CountAsync();

        recentPets = await db.Pets
            .Include(p => p.Owner)
            .OrderByDescending(p => p.Id)
            .Take(5)
            .ToListAsync();

        todaySchedule = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledDateTime.Date == today && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.ScheduledDateTime)
            .ToListAsync();
    }
}

