@code {
    [Parameter] public int PetId { get; set; }

    private Pet? pet;
    private PetEditModel editModel = new();
    private TreatmentFormModel newTreatment = new();
    private bool saveSuccess = false;

    protected override async Task OnInitializedAsync()
    {
        await LoadPet();
    }

    private async Task LoadPet()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pet = await db.Pets
            .Include(p => p.Owner)
            .Include(p => p.TreatmentRecords)
            .FirstOrDefaultAsync(p => p.Id == PetId);

        if (pet != null)
        {
            editModel = new PetEditModel
            {
                Name = pet.Name,
                Species = pet.Species,
                Breed = pet.Breed,
                DateOfBirth = pet.DateOfBirth,
                Notes = pet.Notes
            };
        }
    }

    private async Task SavePetInfo()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var dbPet = await db.Pets.FindAsync(PetId);
        if (dbPet != null)
        {
            dbPet.Name = editModel.Name;
            dbPet.Species = editModel.Species;
            dbPet.Breed = editModel.Breed;
            dbPet.DateOfBirth = editModel.DateOfBirth;
            dbPet.Notes = editModel.Notes;
            await db.SaveChangesAsync();
            saveSuccess = true;
            await LoadPet();
        }
    }

    private async Task AddTreatment()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var record = new TreatmentRecord
        {
            PetId = PetId,
            Date = newTreatment.Date,
            Description = newTreatment.Description,
            Veterinarian = newTreatment.Veterinarian,
            Notes = newTreatment.Notes
        };
        db.TreatmentRecords.Add(record);
        await db.SaveChangesAsync();
        newTreatment = new();
        await LoadPet();
    }

    private class PetEditModel
    {
        [Required] public string Name { get; set; } = string.Empty;
        [Required] public string Species { get; set; } = string.Empty;
        public string? Breed { get; set; }
        public DateTime? DateOfBirth { get; set; }
        public string? Notes { get; set; }
    }

    private class TreatmentFormModel
    {
        [Required] public DateTime Date { get; set; } = DateTime.Today;
        [Required] public string Description { get; set; } = string.Empty;
        public string? Veterinarian { get; set; }
        public string? Notes { get; set; }
    }
}

