@page "/appointments"
@attribute [Authorize]

@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Previous Week</button>
        <button class="btn btn-outline-secondary" @onclick="NextWeek">Next Week &raquo;</button>
    </div>
    <div class="col-md-4 text-center">
        <h5>@weekStart.ToString("MMM dd") - @weekStart.AddDays(6).ToString("MMM dd, yyyy")</h5>
    </div>
    <div class="col-md-4 text-end">
        <button class="btn btn-primary" @onclick="ToggleNewForm">@(showNewForm ? "Cancel" : "New Appointment")</button>
    </div>
</div>

@if (showNewForm)
{
    <div class="card mb-4">
        <div class="card-header">Schedule Appointment</div>
        <div class="card-body">
            <EditForm Model="newAppointment" OnValidSubmit="CreateAppointment" FormName="newAppointment">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label>Pet</label>
                        <InputSelect class="form-control" @bind-Value="newAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var p in allPets)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4">
                        <label>Date & Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="newAppointment.ScheduledDateTime" />
                    </div>
                    <div class="col-md-4">
                        <label>Duration (min)</label>
                        <InputNumber class="form-control" @bind-Value="newAppointment.DurationMinutes" />
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col-md-8">
                        <label>Reason</label>
                        <InputText class="form-control" @bind-Value="newAppointment.Reason" />
                    </div>
                    <div class="col-md-4">
                        <label>Notes</label>
                        <InputText class="form-control" @bind-Value="newAppointment.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Schedule</button>
            </EditForm>
        </div>
    </div>
}

@if (editingAppointment != null)
{
    <div class="card mb-4 border-warning">
        <div class="card-header bg-warning text-dark">Edit Appointment #@editingAppointment.Id</div>
        <div class="card-body">
            <div class="row mb-2">
                <div class="col-md-4">
                    <label>Date & Time</label>
                    <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.ScheduledDateTime" />
                </div>
                <div class="col-md-4">
                    <label>Status</label>
                    <select class="form-control" @bind="editingAppointment.Status">
                        @foreach (var s in Enum.GetValues<AppointmentStatus>())
                        {
                            <option value="@s">@s</option>
                        }
                    </select>
                </div>
                <div class="col-md-4">
                    <label>Notes</label>
                    <input class="form-control" @bind="editingAppointment.Notes" />
                </div>
            </div>
            <button class="btn btn-primary me-2" @onclick="SaveEdit">Save Changes</button>
            <button class="btn btn-danger me-2" @onclick="CancelAppointment">Cancel Appointment</button>
            <button class="btn btn-secondary" @onclick="() => editingAppointment = null">Close</button>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-bordered">
        <thead>
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="@(day.Date == DateTime.Today ? "table-info" : "")">@day.ToString("ddd MM/dd")</th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour <= 17; hour++)
            {
                <tr>
                    <td><strong>@hour:00</strong></td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var slotTime = day.AddHours(hour);
                        var slotAppts = weekAppointments
                            .Where(a => a.ScheduledDateTime >= slotTime && a.ScheduledDateTime < slotTime.AddHours(1))
                            .ToList();
                        <td class="@(slotAppts.Any() ? "" : "table-success")" style="cursor:pointer; font-size:0.85em">
                            @foreach (var appt in slotAppts)
                            {
                                <div class="badge @GetStatusBadge(appt.Status) d-block mb-1" style="cursor:pointer" @onclick="() => EditAppointment(appt)">
                                    @appt.ScheduledDateTime.ToString("HH:mm") @appt.Pet.Name
                                </div>
                            }
                            @if (!slotAppts.Any())
                            {
                                <small class="text-muted">Available</small>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
    private List<Appointment> weekAppointments = new();
    private List<Pet> allPets = new();
    private bool showNewForm = false;
    private AppointmentFormModel newAppointment = new();
    private Appointment? editingAppointment;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var weekEnd = weekStart.AddDays(7);
        weekAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledDateTime >= weekStart && a.ScheduledDateTime < weekEnd && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.ScheduledDateTime)
            .ToListAsync();

        allPets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private void ToggleNewForm()
    {
        showNewForm = !showNewForm;
        if (showNewForm) newAppointment = new();
    }

    private async Task CreateAppointment()
    {
        if (newAppointment.PetId == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var appt = new Appointment
        {
            PetId = newAppointment.PetId,
            ScheduledDateTime = newAppointment.ScheduledDateTime,
            DurationMinutes = newAppointment.DurationMinutes,
            Reason = newAppointment.Reason,
            Notes = newAppointment.Notes,
            Status = AppointmentStatus.Scheduled
        };
        db.Appointments.Add(appt);
        await db.SaveChangesAsync();
        showNewForm = false;
        newAppointment = new();
