@code {
    private List<Invoice> invoices = new();
    private List<Invoice> unpaidInvoices = new();
    private List<Payment> payments = new();
    private List<Pet> allPets = new();
    private string statusFilter = string.Empty;
    private bool showNewInvoice = false;
    private bool showPaymentForm = false;
    private InvoiceFormModel newInvoice = new();
    private PaymentFormModel newPayment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        await LoadInvoices();
        using var db = await DbFactory.CreateDbContextAsync();
        allPets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        payments = await db.Payments.OrderByDescending(p => p.PaymentDate).Take(20).ToListAsync();
    }

    private async Task LoadInvoices()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<InvoiceStatus>(statusFilter, out var status))
        {
            query = query.Where(i => i.Status == status);
        }

        invoices = await query.OrderByDescending(i => i.InvoiceDate).ToListAsync();

        unpaidInvoices = await db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .Where(i => i.Status != InvoiceStatus.Paid)
            .ToListAsync();
    }

    private void ToggleNewInvoice()
    {
        showNewInvoice = !showNewInvoice;
        if (showNewInvoice) newInvoice = new();
    }

    private void TogglePaymentForm()
    {
        showPaymentForm = !showPaymentForm;
        if (showPaymentForm) newPayment = new();
    }

    private async Task CreateInvoice()
    {
        if (newInvoice.PetId == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var invoice = new Invoice
        {
            PetId = newInvoice.PetId,
            InvoiceDate = DateTime.Now,
            DueDate = newInvoice.DueDate,
            Status = InvoiceStatus.Draft,
            Notes = newInvoice.Notes
        };
        foreach (var li in newInvoice.LineItems.Where(l => !string.IsNullOrWhiteSpace(l.Description)))
        {
            invoice.LineItems.Add(new InvoiceLineItem
            {
                Description = li.Description,
                Quantity = li.Quantity,
                UnitPrice = li.UnitPrice
            });
        }
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        showNewInvoice = false;
        newInvoice = new();
        await LoadData();
    }

    private async Task ProcessPayment()
    {
        if (newPayment.InvoiceId == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var payment = new Payment
        {
            InvoiceId = newPayment.InvoiceId,
            Amount = newPayment.Amount,
            PaymentDate = DateTime.Now,
            Method = newPayment.Method,
            Reference = newPayment.Reference
        };
        db.Payments.Add(payment);

        var invoice = await db.Invoices
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == newPayment.InvoiceId);
        if (invoice != null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + newPayment.Amount;
            var total = invoice.LineItems.Sum(li => li.Quantity * li.UnitPrice);
            if (totalPaid >= total)
                invoice.Status = InvoiceStatus.Paid;
            else
                invoice.Status = InvoiceStatus.Sent;
        }

        await db.SaveChangesAsync();
        showPaymentForm = false;
        newPayment = new();
        await LoadData();
    }

    private string GetInvoiceBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Sent => "bg-primary",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };

    private class InvoiceFormModel
    {
        [Range(1, int.MaxValue, ErrorMessage = "Please select a pet")]
        public int PetId { get; set; }
        public DateTime DueDate { get; set; } = DateTime.Today.AddDays(30);
        public string? Notes { get; set; }
        public List<LineItemModel> LineItems { get; set; } = new() { new() };
    }

    private class LineItemModel
    {
        public string Description { get; set; } = string.Empty;
        public decimal Quantity { get; set; } = 1;
        public decimal UnitPrice { get; set; }
    }

    private class PaymentFormModel
    {
        [Range(1, int.MaxValue, ErrorMessage = "Please select an invoice")]
        public int InvoiceId { get; set; }
        [Range(0.01, 1000000)]
        public decimal Amount { get; set; }
        public PaymentMethod Method { get; set; } = PaymentMethod.Card;
        public string? Reference { get; set; }
    }
}

